sys_script.script:
var checkNum   = current.getValue('number');
var module     = current.getValue('module');

if (!checkNum || !module) {
    gs.info('[AIROP] Skipping rebuild - missing number or module.');
} else {
    var libName = 'AROPCheckLibrary_' + module;
    var si = new GlideRecord('sys_script_include');
    si.addQuery('name', libName);
    si.setLimit(1);
    si.query();
    if (!si.next()) {
        gs.error('[AIROP] ' + libName + ' not found.');
    } else {
        var libHeader =
            'var ' + libName + ' = Class.create();\n' +
            libName + '.prototype = {\n' +
            '    initialize: function() {},\n' +
            '    _count: function(table, query) { var gr = new GlideRecord(table); if (query) gr.addEncodedQuery(query); gr.query(); return gr.getRowCount(); },\n' +
            '    _pct: function(num, den) { return den > 0 ? Math.round((num/den)*100) : 0; },\n' +
            '    _daysAgo: function(field, days) { var d = new GlideDateTime(); d.addDaysUTC(-days); return field + String.fromCharCode(60) + d.getValue(); },\n';
        var libFooter = '    type: \'' + libName + '\'\n};' ;
        var checks = new GlideRecord('x_snc_airop_check_definition');
        checks.addQuery('module', module);
        checks.addQuery('is_active', true);
        checks.addQuery('number', '!=', checkNum);
        checks.orderBy('order');
        checks.query();
        var methodBlocks = [];
        var injected = 0;
        while (checks.next()) {
            var num = checks.getValue('number');
            var scr = checks.getValue('check_script');
            if (!num || !scr || scr.trim() === '') continue;
            var trimmed = scr.trim();
            var alreadyCalled = trimmed.endsWith('})()')
                             || trimmed.endsWith('})();');
            var returnStatement = alreadyCalled
                ? 'return ' + trimmed + (trimmed.endsWith(';') ? '' : ';')
                : 'return (' + trimmed + ')();';
            var method =
                '    ' + num + ': function() {\n' +
                '        try {\n' +
                '            ' + returnStatement + '\n' +
                '        } catch(e) {\n' +
                '            return { status: \'needs_attention\', actualValue: \'Script error: \' + e.message, finding: \'Error in ' + num + ': \' + e.message };\n' +
                '        }\n' +
                '    }';
            methodBlocks.push(method);
            injected++;
        }
        var newLibScript = libHeader +
                           (methodBlocks.length > 0 ? methodBlocks.join(',\n') + ',\n' : '') +
                           libFooter;
        si.setValue('script', newLibScript);
        si.setWorkflow(false);
        si.update();
        gs.info('[AIROP] ' + libName + ' rebuilt with ' + injected + ' methods (removed ' + checkNum + ').');
    }
}
